# --- SECURE Redirect URI Validation ---

def validate_redirect_uri_strict(redirect_uri: str, tenant_config: dict) -> bool:
    """
    Securely validate a redirect URI against the tenant's allowed configuration.

    SECURITY NOTES:
    - Uses exact match against an allowlist of pre-registered URIs.
    - NEVER use 'if domain in redirect_uri' — this is vulnerable to:
        * https://evil.com/example.com (path injection)
        * https://example.com.attacker.com (subdomain spoofing)
        * https://attacker.com?q=example.com (query param injection)
    - NEVER use substring/contains checks for security-critical URL validation.
    """
    if not redirect_uri:
        return False

    # Step 1: Parse the URI to validate structure
    try:
        parsed = urlparse(redirect_uri)
    except Exception:
        return False

    # Step 2: Enforce HTTPS (except localhost for development)
    if parsed.scheme != "https":
        if not (parsed.hostname == "localhost" and app.debug):
            return False

    # Step 3: Reject URIs with fragments (OAuth 2.0 spec requirement)
    if parsed.fragment:
        return False

    # Step 4: Reject empty or suspicious hostnames
    if not parsed.hostname:
        return False

    # Step 5: Reject userinfo in URI (e.g., https://attacker.com@example.com)
    if parsed.username or parsed.password:
        return False

    # Step 6: EXACT MATCH against the pre-registered allowlist
    # This is the only secure way to validate redirect URIs
    normalized_uri = f"{parsed.scheme}://{parsed.netloc}{parsed.path}"
    # Remove trailing slash for consistent comparison
    normalized_uri = normalized_uri.rstrip("/")

    allowed_uris_normalized = [
        uri.rstrip("/") for uri in tenant_config.get("allowed_redirect_uris", [])
    ]

    if normalized_uri not in allowed_uris_normalized:
        app.logger.warning(
            f"Redirect URI rejected (not in allowlist): {redirect_uri}"
        )
        return False

    # Step 7: Additionally verify the host matches allowed domains exactly
    # This is defense-in-depth, not a replacement for the allowlist
    if not _is_exact_domain_match(parsed.hostname, tenant_config.get("allowed_domains", [])):
        app.logger.warning(
            f"Redirect URI host rejected (domain mismatch): {parsed.hostname}"
        )
        return False

    return True


def _is_exact_domain_match(hostname: str, allowed_domains: list) -> bool:
    """
    Check if hostname exactly matches one of the allowed domains.

    SECURE: Uses exact string equality — NOT substring matching.
    For subdomain support, explicitly list each allowed subdomain
    in the configuration, or use a suffix check with a leading dot.
    """
    if not hostname or not allowed_domains:
        return False

    hostname = hostname.lower().strip(".")

    for domain in allowed_domains:
        domain = domain.lower().strip(".")
        # Exact match
        if hostname == domain:
            return True
        # Secure subdomain match: hostname must END with ".domain"
        # e.g., "sub.tenant-a.example.com" matches ".example.com"
        # but "tenant-a.example.com.evil.com" does NOT
        # Only enable this if you explicitly want wildcard subdomain support
        # if hostname.endswith(f".{domain}"):
        #     return True

    return False


