# --- PKCE Support ---

def generate_pkce_pair():
    """Generate PKCE code_verifier and code_challenge for enhanced security."""
    code_verifier = secrets.token_urlsafe(64)[:128]
    code_challenge = base64.urlsafe_b64encode(
        hashlib.sha256(code_verifier.encode("ascii")).digest()
    ).decode("ascii").rstrip("=")
    return code_verifier, code_challenge


# --- Helper to get tenant config ---

def get_tenant_config(tenant_id: str) -> dict:
    """Retrieve tenant configuration securely."""
    config = TENANT_CONFIGS.get(tenant_id)
    if not config:
        abort(404, description=f"Unknown tenant: {tenant_id}")
    return config


def require_authenticated(f):
    """Decorator to require an authenticated session."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if "access_token" not in session or "tenant_id" not in session:
            return jsonify({"error": "Authentication required"}), 401
        return f(*args, **kwargs)
    return decorated_function


