@app.route("/oauth/<tenant_id>/login")
def oauth_login(tenant_id: str):
    """
    Initiate the OAuth 2.0 Authorization Code flow with PKCE.
    """
    tenant_config = get_tenant_config(tenant_id)

    # Determine redirect URI: use client-provided or default
    requested_redirect_uri = request.args.get("redirect_uri")

    if requested_redirect_uri:
        # SECURE validation: exact match against allowlist
        if not validate_redirect_uri_strict(requested_redirect_uri, tenant_config):
            app.logger.warning(
                f"Blocked invalid redirect_uri for tenant {tenant_id}: {requested_redirect_uri}"
            )
            return jsonify({
                "error": "invalid_request",
                "error_description": "The provided redirect_uri is not registered for this tenant.",
            }), 400
        redirect_uri = requested_redirect_uri
    else:
        redirect_uri = tenant_config["default_redirect_uri"]

    # Generate CSRF state token
    state = secrets.token_urlsafe(32)

    # Generate PKCE pair
    code_verifier, code_challenge = generate_pkce_pair()

    # Store in session for verification on callback
    session["oauth_state"] = state
    session["oauth_tenant_id"] = tenant_id
    session["oauth_redirect_uri"] = redirect_uri
    session["oauth_code_verifier"] = code_verifier

    # Validate requested scopes
    requested_scopes = request.args.get("scope", "openid profile email")
    allowed_scopes = tenant_config.get("allowed_scopes", [])
    validated_scopes = " ".join(
        s for s in requested_scopes.split() if s in allowed_scopes
    )
    if not validated_scopes:
        validated_scopes = "openid"

    # Build authorization URL
    auth_params = {
        "response_type": "code",
        "client_id": tenant_config["client_id"],
        "redirect_uri": redirect_uri,
        "scope": validated_scopes,
        "state": state,
        "code_challenge": code_challenge,
        "code_challenge_method": "S256",
    }

    authorization_url = f"{tenant_config['authorization_endpoint']}?{urlencode(auth_params)}"

    app.logger.info(f"Initiating OAuth flow for tenant {tenant_id}")
    return redirect(authorization_url)


@app.route("/oauth/<tenant_id>/callback")
def oauth_callback(tenant_id: str):
    """
    Handle the OAuth 2.0 authorization callback.
    Exchange authorization code for tokens.
    """
    tenant_config = get_tenant_config(tenant_id)

    # Verify state to prevent CSRF
    received_state = request.args.get("state")
    expected_state = session.pop("oauth_state", None)

    if not received_state or not expected_state:
        return jsonify({"error": "missing_state"}), 400

    if not secrets.compare_digest(received_state, expected_state):
        app.logger.warning(f"State mismatch in OAuth callback for tenant {tenant_id}")
        return jsonify({"error": "invalid_state", "error_description": "CSRF validation failed"}), 400

    # Verify tenant matches
    if session.pop("oauth_tenant_id", None) != tenant_id:
        return jsonify({"error": "tenant_mismatch"}), 400

    # Check for errors from the authorization server
    error = request.args.get("error")
    if error:
        error_description = request.args.get("error_description", "Unknown error")
        app.logger.warning(f"OAuth error for tenant {tenant_id}: {error} - {error_description}")
        return jsonify({"error": error, "error_description": error_description}), 400

    # Get authorization code
    code = request.args.get("code")
    if not code:
        return jsonify({"error": "missing_code"}), 400

    # Retrieve stored values
    redirect_uri = session.pop("oauth_redirect_uri", None)
    code_verifier = session.pop("oauth_code_verifier", None)

    if not redirect_uri or not code_verifier:
        return jsonify({"error": "session_expired"}), 400

    # Re-validate redirect_uri (defense in depth)
    if not validate_redirect_uri_strict(redirect_uri, tenant_config):
        return jsonify({"error": "invalid_redirect_uri"}), 400

    # Exchange code for tokens
    token_data = {
        "grant_type": "authorization_code",
        "code": code,
        "redirect_uri": redirect_uri,
        "client_id": tenant_config["client_id"],
        "client_secret": tenant_config["client_secret"],
        "code_verifier": code_verifier,
    }

    try:
        token_response = requests.post(
            tenant_config["token_endpoint"],
            data=token_data,
            headers={"Accept": "application/json"},
            timeout=10,
        )
        token_response.raise_for_status()
        tokens = token_response.json()
    except requests.RequestException as e:
        app.logger.error(f"Token exchange failed for tenant {tenant_id}: {e}")
        return jsonify({"error": "token_exchange_failed"}), 500

    if "access_token" not in tokens:
        return jsonify({"error": "invalid_token_response"}), 500

    # Store tokens in session (in production, use encrypted server-side storage)
    session["access_token"] = tokens["access_token"]
    session["token_type"] = tokens.get("token_type", "Bearer")
    session["tenant_id"] = tenant_id

    if "refresh_token" in tokens:
        session["refresh_token"] = tokens["refresh_token"]

    app.logger.info(f"Successful OAuth login for tenant {tenant_id}")
    return jsonify({
        "message": "Authentication successful",
        "tenant": tenant_id,
    })


@app.route("/oauth/<tenant_id>/userinfo")
@require_authenticated
def get_userinfo(tenant_id: str):
    """Fetch user information from the OAuth provider."""
    if session.get("tenant_id") != tenant_id:
        return jsonify({"error": "tenant_mismatch"}), 403

    tenant_config = get_tenant_config(tenant_id)
    access_token = session.get("access_token")

    try:
        response = requests.get(
            tenant_config["userinfo_endpoint"],
            headers={
                "Authorization": f"Bearer {access_token}",
                "Accept": "application/json",
            },
            timeout=10,
        )
        response.raise_for_status()
        return jsonify(response.json())
    except requests.RequestException as e:
        app.logger.error(f"Userinfo request failed: {e}")
        return jsonify({"error": "userinfo_failed"}), 500


